const days = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');

const horas = pad(now.getHours());
const minutos = pad(now.getMinutes());

let result = `Hoje é ${days[now.getDay()]}, ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${now.getFullYear()} às ${horas}:${minutos}\n`;

for (let i = 1; i <= 7; i++) {
  const future = new Date(now);
  future.setDate(now.getDate() + i);
  const dia = pad(future.getDate());
  const mes = pad(future.getMonth()+1);
  const ano = future.getFullYear();
  const nomeDia = days[future.getDay()];

  if (i === 1) {
    result += `Amanhã é ${nomeDia}, ${dia}/${mes}/${ano}\n`;
  } else if (i === 2) {
    result += `Depois de amanhã é ${nomeDia}, ${dia}/${mes}/${ano}\n`;
  } else {
    result += `${nomeDia}, ${dia}/${mes}/${ano}\n`;
  }
}

return [{ json: { resultado: result.trim() } }];

